namespace sv_a635ef8252c1491d90908039e5584e74.Services;

/// <summary>
/// Scoped service (one per circuit) that holds the currently selected warehouse
/// and notifies all subscribers when it changes. Being scoped ensures each user's
/// Blazor Server circuit gets its own independent instance.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — North"),
        ("WH-004", "Warehouse D — South"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>
    /// Raised on the caller's synchronization context whenever the warehouse changes.
    /// </summary>
    public event Func<Task>? OnChanged;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;

        if (OnChanged is not null)
            await OnChanged.Invoke();
    }
}

namespace sv_a635ef8252c1491d90908039e5584e74.Services;

/// <summary>
/// Scoped service that simulates checking a database for low-stock items
/// and broadcasts the latest count to all subscribed components.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random _random = Random.Shared;

    private int _lastCount;
    public int LastCount => _lastCount;

    /// <summary>
    /// Raised when a new alert count is available so every subscriber can re-render.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items below minimum stock.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate DB latency and a random result between 0-15.
        int count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by the polling component to push the latest count and notify all subscribers.
    /// </summary>
    public async Task PublishCountAsync(int count)
    {
        _lastCount = count;

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

