+                        <span class="badge bg-success">Active — every 10s</span>
+                    }
+                    else
+                    {
+                        <span class="badge bg-secondary">Stopped</span>
+                    }
+                </div>
+                <p class="text-muted mt-2">Last checked: @_lastChecked?.ToString("HH:mm:ss")</p>
+            </div>
+        </div>
+    </div>
+</div>
+
+@code {
+    private int _alertCount;
+    private bool _isPolling;
+    private DateTime? _lastChecked;
+    private PeriodicTimer? _timer;
+    private CancellationTokenSource? _cts;
+
+    protected override void OnInitialized()
+    {
+        WarehouseState.OnChanged += HandleWarehouseChanged;
+        AlertService.OnAlertCountChanged += HandleAlertCountChanged;
+    }
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            await StartPollingAsync();
+        }
+    }
+
+    private async Task StartPollingAsync()
+    {
+        StopPolling();
+
+        _cts = new CancellationTokenSource();
+        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
+        _isPolling = true;
+
+        // Fetch immediately, then poll on interval.
+        await FetchAndPublishAsync();
+
+        _ = PollLoopAsync(_cts.Token);
+    }
+
+    private async Task PollLoopAsync(CancellationToken ct)
+    {
+        try
+        {
+            while (await _timer!.WaitForNextTickAsync(ct))
+            {
+                await InvokeAsync(async () =>
+                {
+                    await FetchAndPublishAsync();
+                });
+            }
+        }
+        catch (OperationCanceledException)
+        {
+            // Expected on dispose / warehouse switch.
+        }
+    }
+
+    private async Task FetchAndPublishAsync()
+    {
+        _alertCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
+        _lastChecked = DateTime.Now;
+
+        // Push through the service so the sidebar AlertBadge also updates.
+        await AlertService.PublishCountAsync(_alertCount);
+
+        StateHasChanged();
+    }
+
+    private async Task HandleWarehouseChanged()
+    {
+        // Restart polling for the new warehouse.
+        await InvokeAsync(async () =>
+        {
+            await StartPollingAsync();
+            StateHasChanged();
+        });
+    }
+
+    private Task HandleAlertCountChanged()
+    {
+        InvokeAsync(StateHasChanged);
+        return Task.CompletedTask;
+    }
+
+    private void StopPolling()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = null;
+        _timer?.Dispose();
+        _timer = null;
+        _isPolling = false;
+    }
+
+    public void Dispose()
+    {
+        StopPolling();
+        WarehouseState.OnChanged -= HandleWarehouseChanged;
+        AlertService.OnAlertCountChanged -= HandleAlertCountChanged;
+    }
+}
+

